    def _sort_palette(self, sort_palette):
        """
        Sorts the palette of this "P" mode image in place, remapping pixel
        indices to match the new color order.

        :param sort_palette: ``"luminance"`` to sort colors by perceptual
           brightness, or ``"rgb"`` to sort colors by their raw RGB value.
        """
        mode_len = len(self.palette.mode)
        palette = self.palette.palette
        colors = [
            tuple(palette[i : i + mode_len])
            for i in range(0, len(palette), mode_len)
        ]

        if sort_palette == "luminance":

            def sort_key(color):
                r, g, b = color[:3]
                return r * 299 + g * 587 + b * 114

        elif sort_palette == "rgb":

            def sort_key(color):
                return color

        else:
            raise ValueError(f"Unsupported sort_palette value: {sort_palette!r}")

