        for new_index, old_index in enumerate(order):
            mapping[old_index] = new_index

        new_palette = bytearray()
        for old_index in order:
            new_palette.extend(colors[old_index])

        from . import ImagePalette

        self.im = self.point(mapping).im
        self.palette = ImagePalette.ImagePalette(self.palette.mode, bytes(new_palette))

